--
-- All inserts use ON CONFLICT DO NOTHING — file is idempotent.

CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- ─────────────────────────────────────────────────────────────────────────
-- SCHEMA
-- ─────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS agent_profiles (
  id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name              TEXT NOT NULL,
  slug              TEXT UNIQUE NOT NULL,
  description       TEXT,
  system_prompt     TEXT NOT NULL DEFAULT '',
  model_tier        TEXT NOT NULL DEFAULT 'strong',
  model_override    TEXT,
  allowed_tools     JSONB NOT NULL DEFAULT '[]',
  behavior_settings JSONB NOT NULL DEFAULT '{}',
  tags              JSONB NOT NULL DEFAULT '[]',
  built_in          BOOLEAN NOT NULL DEFAULT false,
  created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS profile_config_files (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  profile_id UUID NOT NULL REFERENCES agent_profiles(id) ON DELETE CASCADE,
  file_type  TEXT NOT NULL CHECK (file_type IN ('identity','soul','user','state','directives','decisions','coordination','governance','memory','history','permissions','profile','prompt','links','heartbeat','capabilities','scratch')),
  content    TEXT NOT NULL DEFAULT '',
  UNIQUE (profile_id, file_type)
);

CREATE TABLE IF NOT EXISTS agent_identities (
  id                          TEXT PRIMARY KEY,
  name                        TEXT NOT NULL,
  slug                        TEXT UNIQUE NOT NULL,
  parent_agent_id             TEXT,
  lifecycle_type              TEXT NOT NULL DEFAULT 'always_on',
  wake_mode                   TEXT NOT NULL DEFAULT 'auto',
  current_profile_id          TEXT,
  shell_permission_level      TEXT NOT NULL DEFAULT 'none',
  agent_management_permission TEXT NOT NULL DEFAULT 'approval_required',
  agency_permissions          JSONB NOT NULL DEFAULT '{}',
  autonomous_mode             BOOLEAN NOT NULL DEFAULT false,
  workspace_path              TEXT NOT NULL,
  additional_workspace_paths  JSONB NOT NULL DEFAULT '[]',
  status                      TEXT NOT NULL DEFAULT 'active',
  created_by                  TEXT NOT NULL DEFAULT 'system',
  created_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  brain_node_id               UUID,
  model_config                JSONB,
  schedule                    TEXT,
  schedule_enabled            BOOLEAN NOT NULL DEFAULT false,
  last_run_at                 TIMESTAMPTZ,
  next_run_at                 TIMESTAMPTZ,
  run_count                   INT NOT NULL DEFAULT 0,
  last_error                  TEXT
);

CREATE TABLE IF NOT EXISTS agent_config_files (
  id            UUID    PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id      TEXT    NOT NULL REFERENCES agent_identities(id) ON DELETE CASCADE,
  file_type     TEXT    NOT NULL CHECK (file_type IN ('identity','soul','user','state','directives','decisions','coordination','governance','memory','history','permissions','profile','prompt','links','heartbeat','capabilities','scratch')),
  content       TEXT    NOT NULL DEFAULT '',
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_by    TEXT    NOT NULL DEFAULT 'system',
  brain_node_id UUID,
  UNIQUE (agent_id, file_type)
);

CREATE TABLE IF NOT EXISTS sessions (
  id               TEXT PRIMARY KEY,
  agent_id         TEXT NOT NULL,
  client           TEXT NOT NULL DEFAULT 'cli',
  status           TEXT NOT NULL DEFAULT 'active',
  name             TEXT,
  coordinator_mode BOOLEAN NOT NULL DEFAULT false,
  pinned           BOOLEAN NOT NULL DEFAULT false,
  pinned_at        TIMESTAMPTZ,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS messages (
  id         TEXT PRIMARY KEY,
  session_id TEXT NOT NULL REFERENCES sessions(id),
  role       TEXT NOT NULL,
  content    TEXT NOT NULL DEFAULT '',
  tool_calls JSONB,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS approvals (
  id           TEXT PRIMARY KEY,
  agent_id     TEXT NOT NULL,
  session_id   TEXT NOT NULL,
  prompt       TEXT NOT NULL,
  tool_name    TEXT,
  tool_input   JSONB,
  status       TEXT NOT NULL DEFAULT 'pending',
  risk_level   TEXT NOT NULL DEFAULT 'medium',
  requested_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  resolved_at  TIMESTAMPTZ,
  resolved_by  TEXT,
  note         TEXT
);

CREATE TABLE IF NOT EXISTS model_usage (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id      TEXT NOT NULL,
  session_id    TEXT,
  model         TEXT NOT NULL,
  input_tokens  INT NOT NULL DEFAULT 0,
  output_tokens INT NOT NULL DEFAULT 0,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS skills (
  id                    UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name                  TEXT UNIQUE NOT NULL,
  version               TEXT NOT NULL DEFAULT '0.0.1',
  status                TEXT NOT NULL DEFAULT 'installed',
  type                  TEXT,
  anthropic_builtin_type TEXT,
  anthropic_beta_header  TEXT,
  manifest              JSONB NOT NULL DEFAULT '{}',
  installed_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at            TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS agent_skills (
  agent_id TEXT NOT NULL,
  skill_id UUID NOT NULL REFERENCES skills(id) ON DELETE CASCADE,
  enabled  BOOLEAN NOT NULL DEFAULT true,
  PRIMARY KEY (agent_id, skill_id)
);

CREATE TABLE IF NOT EXISTS memory_entries (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id      TEXT NOT NULL,
  type          TEXT NOT NULL DEFAULT 'episodic'
                CHECK (type IN ('episodic','semantic','working','procedural','reflective')),
  content       TEXT NOT NULL,
  embedding     JSONB,
  tags          JSONB NOT NULL DEFAULT '[]',
  importance    FLOAT NOT NULL DEFAULT 0.5,
  memory_status TEXT NOT NULL DEFAULT 'active'
                CHECK (memory_status IN ('active','proposal','canon','deprecated','archived')),
  scope_type    TEXT NOT NULL DEFAULT 'agent'
                CHECK (scope_type IN ('system','agent','zone','global')),
  scope_id      TEXT,
  visibility    TEXT NOT NULL DEFAULT 'private'
                CHECK (visibility IN ('private','zone','global')),
  trust_level   SMALLINT NOT NULL DEFAULT 1,
  promoted_by   TEXT,
  promoted_at   TIMESTAMPTZ,
  brain_node_id UUID,
  expires_at    TIMESTAMPTZ,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS vault_documents (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  path        TEXT UNIQUE NOT NULL,
  title       TEXT NOT NULL DEFAULT '',
  content     TEXT NOT NULL DEFAULT '',
  frontmatter JSONB NOT NULL DEFAULT '{}',
  status      TEXT NOT NULL DEFAULT 'active',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS vault_entities (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  document_id UUID NOT NULL REFERENCES vault_documents(id) ON DELETE CASCADE,
  name        TEXT NOT NULL,
  type        TEXT NOT NULL,
  properties  JSONB NOT NULL DEFAULT '{}',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE(document_id)
);

CREATE TABLE IF NOT EXISTS vault_links (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  from_doc   UUID NOT NULL REFERENCES vault_documents(id) ON DELETE CASCADE,
  to_doc     UUID NOT NULL REFERENCES vault_documents(id) ON DELETE CASCADE,
  link_text  TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);


CREATE TABLE IF NOT EXISTS audit_log (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  action      TEXT NOT NULL,
  actor       TEXT NOT NULL,
  target_type TEXT,
  target_id   TEXT,
  details     JSONB,
  sensitive   BOOLEAN NOT NULL DEFAULT false,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS hooks (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event      TEXT NOT NULL,
  agent_id   TEXT,
  command    TEXT NOT NULL,
  enabled    BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS tool_overrides (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_id   TEXT NOT NULL,
  tool_name  TEXT NOT NULL,
  override   JSONB NOT NULL DEFAULT '{}',
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (agent_id, tool_name)
);

CREATE TABLE IF NOT EXISTS mcp_servers (
  id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name       TEXT UNIQUE NOT NULL,
  config     JSONB NOT NULL DEFAULT '{}',
  enabled    BOOLEAN NOT NULL DEFAULT true,
  status     TEXT NOT NULL DEFAULT 'disconnected',
  error      TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS agent_mcp (
  agent_id  TEXT NOT NULL,
  server_id UUID NOT NULL REFERENCES mcp_servers(id) ON DELETE CASCADE,
  PRIMARY KEY (agent_id, server_id)
);

CREATE TABLE IF NOT EXISTS workspace_groups (
  id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name           TEXT NOT NULL,
  slug           TEXT UNIQUE NOT NULL,
  description    TEXT,
  workspace_path TEXT NOT NULL,
  is_system      BOOLEAN NOT NULL DEFAULT false,
  brain_node_id  UUID,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at     TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS workspace_group_members (
  group_id UUID NOT NULL REFERENCES workspace_groups(id) ON DELETE CASCADE,
  agent_id TEXT NOT NULL,
  PRIMARY KEY (group_id, agent_id)
);

CREATE TABLE IF NOT EXISTS scheduled_tasks (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  agent_slug  TEXT NOT NULL,
  label       TEXT NOT NULL,
  schedule    TEXT NOT NULL,
  type        TEXT NOT NULL DEFAULT 'recurring',
  prompt      TEXT NOT NULL,
  enabled     BOOLEAN NOT NULL DEFAULT true,
  last_run_at TIMESTAMPTZ,
  next_run_at TIMESTAMPTZ,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS brain_nodes (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  type        TEXT NOT NULL,
  label       TEXT NOT NULL,
  content     TEXT NOT NULL DEFAULT '',
  tags        JSONB NOT NULL DEFAULT '[]',
  embedding   JSONB,
  metadata    JSONB NOT NULL DEFAULT '{}',
  confidence  FLOAT NOT NULL DEFAULT 1.0,
  source      TEXT NOT NULL DEFAULT 'system',
  grid_path   TEXT,
  grid_tier   SMALLINT NOT NULL DEFAULT 0,
  grid_locked BOOLEAN NOT NULL DEFAULT false,
  version     INT NOT NULL DEFAULT 1,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS brain_edges (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  from_id       UUID NOT NULL REFERENCES brain_nodes(id) ON DELETE CASCADE,
  to_id         UUID NOT NULL REFERENCES brain_nodes(id) ON DELETE CASCADE,
  type          TEXT NOT NULL,
  weight        FLOAT NOT NULL DEFAULT 1.0,
  bidirectional BOOLEAN NOT NULL DEFAULT false,
  metadata      JSONB NOT NULL DEFAULT '{}',
  source        TEXT NOT NULL DEFAULT 'system',
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (from_id, to_id, type)
);

CREATE TABLE IF NOT EXISTS brain_node_history (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  node_id     UUID NOT NULL REFERENCES brain_nodes(id) ON DELETE CASCADE,
  content     TEXT,
  metadata    JSONB NOT NULL DEFAULT '{}',
  confidence  FLOAT NOT NULL DEFAULT 1.0,
  changed_by  TEXT NOT NULL DEFAULT 'system',
  changed_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  version     INT NOT NULL DEFAULT 1
);

CREATE TABLE IF NOT EXISTS routing_profiles (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  description TEXT NOT NULL DEFAULT '',
  chain       JSONB NOT NULL DEFAULT '[]',
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ─────────────────────────────────────────────────────────────────────────
-- INDEXES
-- ─────────────────────────────────────────────────────────────────────────

CREATE UNIQUE INDEX IF NOT EXISTS brain_nodes_grid_path_unique_idx ON brain_nodes(grid_path) WHERE grid_path IS NOT NULL;
CREATE INDEX IF NOT EXISTS brain_nodes_grid_tier_idx ON brain_nodes(grid_tier) WHERE grid_tier > 0;
CREATE INDEX IF NOT EXISTS idx_sessions_agent_id ON sessions(agent_id);
CREATE INDEX IF NOT EXISTS idx_messages_session_id ON messages(session_id);
CREATE INDEX IF NOT EXISTS idx_approvals_status ON approvals(status);
CREATE INDEX IF NOT EXISTS idx_approvals_agent_id ON approvals(agent_id);
CREATE INDEX IF NOT EXISTS acf_agent_id_idx ON agent_config_files(agent_id);
CREATE INDEX IF NOT EXISTS pcf_profile_id_idx ON profile_config_files(profile_id);
CREATE INDEX IF NOT EXISTS ai_brain_node_id_idx ON agent_identities(brain_node_id) WHERE brain_node_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS me_memory_status_idx ON memory_entries(memory_status);
CREATE INDEX IF NOT EXISTS me_scope_idx ON memory_entries(scope_type, scope_id);

