-- ─────────────────────────────────────────────────────────────────────────

INSERT INTO brain_edges (from_id, to_id, type, source)
SELECT
  p.id,
  c.id,
  $seed$contains$seed$,
  $seed$system$seed$
FROM brain_nodes p, brain_nodes c
WHERE p.grid_path = $seed$GRID/SYSTEM$seed$
  AND c.grid_path = $seed$GRID/SYSTEM/SYST$seed$
ON CONFLICT (from_id, to_id, type) DO NOTHING;

